hooks.command:
node -e "
const fs = require('fs');
const path = require('path');

const reviewPath = path.join(process.cwd(), 'docs', 'security', 'SECURITY-REVIEW.md');

if (!fs.existsSync(reviewPath)) {
  console.error('HOOK BLOCKED: docs/security/SECURITY-REVIEW.md does not exist.');
  console.error('A security review is required before deploying to any environment.');
  console.error('Action: Invoke security-engineer to produce SECURITY-REVIEW.md.');
  process.exit(2);
}

const content = fs.readFileSync(reviewPath, 'utf8');

// Check for unresolved CRITICAL findings
// Pattern: a CRITICAL finding heading followed by Status: Unresolved
const lines = content.split('\n');
let inCriticalFinding = false;
let unresolvedCriticals = [];
let currentFindingTitle = '';

for (const line of lines) {
  if (line.match(/###.*CRITICAL.*FINDING/i) || line.match(/###.*FINDING.*CRITICAL/i)) {
    inCriticalFinding = true;
    currentFindingTitle = line.replace(/^###\s*/, '').trim();
  } else if (line.match(/^###/)) {
    inCriticalFinding = false;
    currentFindingTitle = '';
  }

  if (inCriticalFinding && line.match(/Status:\s*Unresolved/i)) {
    unresolvedCriticals.push(currentFindingTitle);
  }
}

if (unresolvedCriticals.length > 0) {
  console.error('HOOK BLOCKED: Unresolved CRITICAL security findings detected.');
  console.error('The following CRITICAL findings must be resolved before deployment:');
  unresolvedCriticals.forEach(function(f) { console.error('  - ' + f); });
  console.error('Action: Return to security-engineer to remediate findings.');
  console.error('Note: CRITICAL findings cannot be waived with an ADR — remediation is required.');
  process.exit(2);
}

process.exit(0);
"
